from __future__ import annotations


def correlate_events(events, *, within: int, chain_types=None):
    ordered = sorted(events, key=lambda row: row['ts'])
    if chain_types is None:
        out = []
        for index, event in enumerate(ordered):
            if event.get('type') == 'A':
                for candidate in ordered[index + 1:]:
                    if candidate.get('session_id') == event.get('session_id') and candidate.get('type') == 'B' and candidate['ts'] - event['ts'] <= within:
                        out.append((event, candidate))
                        break
        return out
    chains = []
    for event in ordered:
        if event.get('type') != chain_types[0]:
            continue
        chain = [event]
        cursor = event
        for expected in chain_types[1:]:
            match = None
            for candidate in ordered:
                if candidate.get('session_id') == cursor.get('session_id') and candidate.get('type') == expected and 0 < candidate['ts'] - cursor['ts'] <= within:
                    match = candidate
                    break
            if match is None:
                chain = []
                break
            chain.append(match)
            cursor = match
        if chain:
            chains.append(chain)
    return chains

